String generateUuid() {
  final Random random = Random();
  final StringBuffer buffer = StringBuffer();

  // Generate 32 hexadecimal characters (128 bits) in groups, separated by hyphens
  // Format: 8-4-4-4-12 (32 characters + 4 hyphens = 36 characters)
  // UUID version 4 structure: xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
  // where 'x' is any hexadecimal digit and 'y' is one of '8', '9', 'a', or 'b'.

  // Helper to generate a specified number of random hex characters
  String generateHex(int length) {
    final StringBuffer hexBuffer = StringBuffer();
    for (int i = 0; i < length; i++) {
      hexBuffer.write(random.nextInt(16).toRadixString(16));
    }
    return hexBuffer.toString();
  }

  // 1. First 8 characters
  buffer.write(generateHex(8));
  buffer.write('-');

  // 2. Next 4 characters
  buffer.write(generateHex(4));
  buffer.write('-');

  // 3. Version (4xxx)
  // The first character must be '4' for UUID v4
  buffer.write('4');
  buffer.write(generateHex(3));
  buffer.write('-');

  // 4. Variant (yxxx where y is 8, 9, A, or B)
  // The first character must be 8, 9, a, or b
  final int variantChar = random.nextInt(4); // 0, 1, 2, 3
  if (variantChar == 0) {
    buffer.write('8');
  } else if (variantChar == 1) {
    buffer.write('9');
  } else if (variantChar == 2) {
    buffer.write('a');
  } else { // variantChar == 3
    buffer.write('b');
  }
  buffer.write(generateHex(3));
  buffer.write('-');

  // 5. Last 12 characters
  buffer.write(generateHex(12));

  return buffer.toString();
}

